css:
.loader {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  border: 2px solid;
  box-sizing: border-box;
  border-radius: 50%;
  display: grid;
  animation: l11 1.5s infinite linear;
  transform-origin: 50% 80%;
}.loader:before,.loader:after {content: "";
  grid-area: 1/1;
  border: inherit;
  border-radius: 50%;
  animation: inherit;
  animation-duration: 1s;
  transform-origin: inherit;
}.loader:before {--s:-1;
}@keyframes l11 {100% {transform: scale(calc(var(--s,1)*1turn))}}
